// Shared types for ud-audit-agent

export interface Site {
  id: string;
  name: string;
  url: string;
  repoUrl: string;
  repoOwner: string;
  repoName: string;
  branch: string;
  auditPath: string;
}

export type JobStatus = "pending" | "claimed" | "running" | "completed" | "failed" | "retrying";

export interface Job {
  id: string;
  siteId: string;
  status: JobStatus;
  attempts: number;
  maxAttempts: number;
  createdAt: string;
  updatedAt: string;
  nextRetryAt: string | null;
  error: string | null;
  auditMonth: string; // YYYY-MM
}

export type Severity = "critical" | "warning" | "info";

export interface AuditFinding {
  rule: string;
  severity: Severity;
  description: string;
  url?: string;
  element?: string;
  score?: number;
}

export interface LighthouseScore {
  performance: number;
  accessibility: number;
  bestPractices: number;
  seo: number;
  pwa: number;
}

export interface LighthouseResult {
  formFactor: "mobile" | "desktop";
  scores: LighthouseScore;
  findings: AuditFinding[];
  rawUrl?: string;
}

export interface SeoResult {
  findings: AuditFinding[];
  metaTags: Record<string, string>;
  hasSitemap: boolean;
  hasRobotsTxt: boolean;
  structuredDataValid: boolean;
}

export interface A11yResult {
  findings: AuditFinding[];
  totalViolations: number;
  totalPasses: number;
}

export interface DependencyInfo {
  name: string;
  current: string;
  latest: string;
  type: "patch" | "minor" | "major";
  isSafeUpdate: boolean;
}

export interface DependencyResult {
  findings: AuditFinding[];
  dependencies: DependencyInfo[];
  safeUpdates: DependencyInfo[];
}

export interface AuditResult {
  siteId: string;
  auditMonth: string;
  timestamp: string;
  lighthouse: {
    mobile: LighthouseResult | null;
    desktop: LighthouseResult | null;
  };
  seo: SeoResult | null;
  a11y: A11yResult | null;
  dependencies: DependencyResult | null;
  error: string | null;
}

export interface Fix {
  type: string;
  description: string;
  filePath: string;
  severity: Severity;
  applied: boolean;
  error?: string;
}

export interface JobProcessorResult {
  jobId: string;
  siteId: string;
  success: boolean;
  auditResult: AuditResult | null;
  fixesApplied: Fix[];
  prUrl: string | null;
  error: string | null;
}

export interface ServiceConfig {
  sites: Site[];
  github: {
    token: string;
    defaultPrBranch: string;
  };
  sentry: {
    dsn: string | null;
  };
  server: {
    port: number;
    host: string;
  };
  cron: {
    schedule: string;
    enabled: boolean;
  };
  workDir: string;
  maxRetries: number;
  retryBackoffMs: number;
}

import { z } from "zod";
import type { Site, ServiceConfig } from "./types.js";

const SiteSchema = z.object({
  id: z.string().min(1),
  name: z.string().min(1),
  url: z.string().url(),
  repoUrl: z.string().url(),
  repoOwner: z.string().min(1),
  repoName: z.string().min(1),
  branch: z.string().default("main"),
  auditPath: z.string().default("/"),
});

const EnvSchema = z.object({
  PORT: z.coerce.number().default(3000),
  HOST: z.string().default("0.0.0.0"),
  GITHUB_TOKEN: z.string().min(1),
  GITHUB_DEFAULT_PR_BRANCH: z.string().default("ud-audit"),
  SENTRY_DSN: z.string().optional(),
  CRON_SCHEDULE: z.string().default("0 0 1 * *"), // midnight on 1st of each month
  CRON_ENABLED: z.coerce.boolean().default(true),
  SITES_CONFIG: z.string().optional(),
  WORK_DIR: z.string().default("/tmp/ud-audit-work"),
  MAX_RETRIES: z.coerce.number().default(3),
  RETRY_BACKOFF_MS: z.coerce.number().default(60000),
});

export type EnvVars = z.infer<typeof EnvSchema>;

function parseSitesConfig(raw: string | undefined): Site[] {
  if (!raw) return [];

  // If it looks like JSON, parse it as an array
  if (raw.trim().startsWith("[")) {
    const parsed = JSON.parse(raw);
    return z.array(SiteSchema).parse(parsed);
  }

  // Otherwise treat as comma-separated site IDs and build from env vars
  // Format: SITE_<ID>_URL, SITE_<ID>_REPO_URL, etc.
  const siteIds = raw.split(",").map((s) => s.trim()).filter(Boolean);
  const sites: Site[] = [];

  for (const id of siteIds) {
    const upper = id.toUpperCase().replace(/-/g, "_");
    const url = process.env[`SITE_${upper}_URL`];
    const repoUrl = process.env[`SITE_${upper}_REPO_URL`];
    const repoOwner = process.env[`SITE_${upper}_REPO_OWNER`];
    const repoName = process.env[`SITE_${upper}_REPO_NAME`];

    if (!url || !repoUrl) {
      continue;
    }

    // Parse owner/name from repo URL if not explicitly set
    let owner = repoOwner;
    let name = repoName;
    if (!owner || !name) {
      const match = repoUrl.match(/github\.com[:/]([^/]+)\/([^/]+?)(?:\.git)?$/);
      if (match) {
        owner = owner || match[1];
        name = name || match[2];
      }
    }

    if (!owner || !name) {
      continue;
    }

    sites.push({
      id,
      name: process.env[`SITE_${upper}_NAME`] || id,
      url,
      repoUrl,
      repoOwner: owner,
      repoName: name,
      branch: process.env[`SITE_${upper}_BRANCH`] || "main",
      auditPath: process.env[`SITE_${upper}_AUDIT_PATH`] || "/",
    });
  }

  return sites;
}

export function loadConfig(): ServiceConfig {
  const env = EnvSchema.parse(process.env);

  const sites: Site[] = env.SITES_CONFIG
    ? parseSitesConfig(env.SITES_CONFIG)
    : [];

  return {
    sites,
    github: {
      token: env.GITHUB_TOKEN,
      defaultPrBranch: env.GITHUB_DEFAULT_PR_BRANCH,
    },
    sentry: {
      dsn: env.SENTRY_DSN || null,
    },
    server: {
      port: env.PORT,
      host: env.HOST,
    },
    cron: {
      schedule: env.CRON_SCHEDULE,
      enabled: env.CRON_ENABLED,
    },
    workDir: env.WORK_DIR,
    maxRetries: env.MAX_RETRIES,
    retryBackoffMs: env.RETRY_BACKOFF_MS,
  };
}

export function validateConfig(config: ServiceConfig): void {
  if (config.sites.length === 0) {
    throw new Error(
      "No sites configured. Set SITES_CONFIG env var with site IDs, or provide a JSON config.",
    );
  }
  if (!config.github.token) {
    throw new Error("GITHUB_TOKEN is required");
  }
}

import pino, { type Logger } from "pino";

let logger: Logger | null = null;

export function getLogger(): Logger {
  if (!logger) {
    logger = pino({
      level: process.env.LOG_LEVEL || "info",
      transport:
        process.env.NODE_ENV === "production"
          ? undefined
          : {
              target: "pino-pretty",
              options: {
                colorize: true,
                translateTime: "SYS:standard",
                ignore: "pid,hostname",
              },
            },
    });
  }
  return logger;
}

export function createChildLogger(bindings: Record<string, unknown>): Logger {
  return getLogger().child(bindings);
}

import Database from "better-sqlite3";
import { randomUUID } from "crypto";
import type { Job, JobStatus } from "./types.js";
import { getLogger } from "./logger.js";

const log = getLogger().child({ module: "queue" });

const CREATE_TABLE = `
  CREATE TABLE IF NOT EXISTS jobs (
    id TEXT PRIMARY KEY,
    site_id TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'pending',
    attempts INTEGER NOT NULL DEFAULT 0,
    max_attempts INTEGER NOT NULL DEFAULT 3,
    created_at TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at TEXT NOT NULL DEFAULT (datetime('now')),
    next_retry_at TEXT,
    error TEXT,
    audit_month TEXT NOT NULL
  );
`;

const CREATE_INDEXES = `
  CREATE INDEX IF NOT EXISTS idx_jobs_status ON jobs(status);
  CREATE INDEX IF NOT EXISTS idx_jobs_site_status ON jobs(site_id, status);
  CREATE INDEX IF NOT EXISTS idx_jobs_audit_month ON jobs(audit_month);
`;

export class JobQueue {
  private db: Database.Database;

  constructor(dbPath: string = ":memory:") {
    this.db = new Database(dbPath);
    this.db.pragma("journal_mode = WAL");
    this.db.pragma("foreign_keys = ON");
    this.db.exec(CREATE_TABLE);
    this.db.exec(CREATE_INDEXES);
    log.info({ dbPath }, "Job queue initialized");
  }

  create(siteId: string, auditMonth: string, maxAttempts: number = 3): Job {
    const now = new Date().toISOString();
    const job: Job = {
      id: randomUUID(),
      siteId,
      status: "pending",
      attempts: 0,
      maxAttempts,
      createdAt: now,
      updatedAt: now,
      nextRetryAt: null,
      error: null,
      auditMonth,
    };

    this.db.prepare(
      `INSERT INTO jobs (id, site_id, status, attempts, max_attempts, created_at, updated_at, next_retry_at, error, audit_month)
       VALUES (@id, @siteId, @status, @attempts, @maxAttempts, @createdAt, @updatedAt, @nextRetryAt, @error, @auditMonth)`,
    ).run({
      id: job.id,
      siteId: job.siteId,
      status: job.status,
      attempts: job.attempts,
      maxAttempts: job.maxAttempts,
      createdAt: job.createdAt,
      updatedAt: job.updatedAt,
      nextRetryAt: job.nextRetryAt,
      error: job.error,
      auditMonth: job.auditMonth,
    });

    log.info({ jobId: job.id, siteId, auditMonth }, "Job created");
    return job;
  }

  claim(jobId: string): Job | null {
    const result = this.db.prepare(
      `UPDATE jobs SET status = 'claimed', updated_at = datetime('now'), attempts = attempts + 1
       WHERE id = ? AND status IN ('pending', 'retrying')
       RETURNING *`,
    ).get(jobId) as Record<string, unknown> | undefined;

    if (!result) {
      return null;
    }

    return this.rowToJob(result);
  }

  markRunning(jobId: string): Job | null {
    const result = this.db.prepare(
      `UPDATE jobs SET status = 'running', updated_at = datetime('now')
       WHERE id = ? AND status = 'claimed'
       RETURNING *`,
    ).get(jobId) as Record<string, unknown> | undefined;

    if (!result) return null;
    return this.rowToJob(result);
  }

  complete(jobId: string): Job | null {
    const result = this.db.prepare(
      `UPDATE jobs SET status = 'completed', updated_at = datetime('now')
       WHERE id = ? AND status = 'running'
       RETURNING *`,
    ).get(jobId) as Record<string, unknown> | undefined;

    if (!result) return null;
    const job = this.rowToJob(result);
    log.info({ jobId }, "Job completed");
    return job;
  }

  fail(jobId: string, error: string): Job | null {
    const result = this.db.prepare(
      `UPDATE jobs SET status = 'failed', updated_at = datetime('now'), error = ?
       WHERE id = ? AND status = 'running'
       RETURNING *`,
    ).get(error, jobId) as Record<string, unknown> | undefined;

    if (!result) return null;
    const job = this.rowToJob(result);
    log.error({ jobId, error }, "Job failed");
    return job;
  }

  scheduleRetry(jobId: string, backoffMs: number): Job | null {
    const job = this.get(jobId);
    if (!job) return null;

    const nextRetryAt = new Date(Date.now() + backoffMs).toISOString();
    const status: JobStatus = job.attempts >= job.maxAttempts ? "failed" : "retrying";

    const result = this.db.prepare(
      `UPDATE jobs SET status = ?, updated_at = datetime('now'), next_retry_at = ?
       WHERE id = ?
       RETURNING *`,
    ).get(status, nextRetryAt, jobId) as Record<string, unknown> | undefined;

    if (!result) return null;
    const updated = this.rowToJob(result);
    log.info({ jobId, status, nextRetryAt, attempts: updated.attempts }, "Job retry scheduled");
    return updated;
  }

  get(jobId: string): Job | null {
    const row = this.db.prepare("SELECT * FROM jobs WHERE id = ?").get(jobId) as
      | Record<string, unknown>
      | undefined;
    return row ? this.rowToJob(row) : null;
  }

  getBySiteAndMonth(siteId: string, auditMonth: string): Job | null {
    const row = this.db.prepare(
      "SELECT * FROM jobs WHERE site_id = ? AND audit_month = ? ORDER BY created_at DESC LIMIT 1",
    ).get(siteId, auditMonth) as Record<string, unknown> | undefined;
    return row ? this.rowToJob(row) : null;
  }

  getPendingRetries(): Job[] {
    const rows = this.db.prepare(
      `SELECT * FROM jobs WHERE status = 'retrying' AND next_retry_at <= datetime('now')
       ORDER BY created_at ASC`,
    ).all() as Record<string, unknown>[];
    return rows.map((r) => this.rowToJob(r));
  }

  getAll(): Job[] {
    const rows = this.db.prepare("SELECT * FROM jobs ORDER BY created_at DESC").all() as
      | Record<string, unknown>[];
    return rows.map((r) => this.rowToJob(r));
  }

  countByStatus(status: JobStatus): number {
    const row = this.db.prepare("SELECT COUNT(*) as count FROM jobs WHERE status = ?").get(
      status,
    ) as { count: number };
    return row.count;
  }

  close(): void {
    this.db.close();
    log.info("Job queue closed");
  }

  private rowToJob(row: Record<string, unknown>): Job {
    return {
      id: row.id as string,
      siteId: row.site_id as string,
      status: row.status as JobStatus,
      attempts: row.attempts as number,
      maxAttempts: row.max_attempts as number,
      createdAt: row.created_at as string,
      updatedAt: row.updated_at as string,
      nextRetryAt: (row.next_retry_at as string) || null,
      error: (row.error as string) || null,
      auditMonth: row.audit_month as string,
    };
  }
}

import { Octokit } from "@octokit/rest";
import type { ServiceConfig } from "./types.js";
import { getLogger } from "./logger.js";

const log = getLogger().child({ module: "github" });

export class GitHubClient {
  private octokit: Octokit;
  private defaultBranch: string;

  constructor(config: ServiceConfig) {
    this.octokit = new Octokit({
      auth: config.github.token,
    });
    this.defaultBranch = config.github.defaultPrBranch;
    log.info("GitHub client initialized");
  }

  async ensureBranch(
    owner: string,
    repo: string,
    baseBranch: string,
    branchName: string,
  ): Promise<{ sha: string }> {
    log.info({ owner, repo, baseBranch, branchName }, "Ensuring branch exists");

    // Get the latest commit SHA from base branch
    const { data: ref } = await this.octokit.git.getRef({
      owner,
      repo,
      ref: `heads/${baseBranch}`,
    });

    const baseSha = ref.object.sha;

    // Check if branch already exists
    try {
      await this.octokit.git.getRef({
        owner,
        repo,
        ref: `heads/${branchName}`,
      });
      // Branch exists, reset it to base
      await this.octokit.git.updateRef({
        owner,
        repo,
        ref: `heads/${branchName}`,
        sha: baseSha,
        force: true,
      });
      log.info({ branchName }, "Branch reset to base");
    } catch {
      // Branch doesn't exist, create it
      await this.octokit.git.createRef({
        owner,
        repo,
        ref: `refs/heads/${branchName}`,
        sha: baseSha,
      });
      log.info({ branchName }, "Branch created");
    }

    return { sha: baseSha };
  }

  async createOrUpdateFile(
    owner: string,
    repo: string,
    branch: string,
    path: string,
    content: string,
    message: string,
  ): Promise<{ sha: string }> {
    // Try to get existing file SHA for updates
    let sha: string | undefined;
    try {
      const { data: file } = await this.octokit.repos.getContent({
        owner,
        repo,
        path,
        ref: branch,
      });
      if ("sha" in file) {
        sha = file.sha;
      }
    } catch {
      // File doesn't exist, will be created
    }

    const encoded = Buffer.from(content).toString("base64");

    const { data } = await this.octokit.repos.createOrUpdateFileContents({
      owner,
      repo,
      path,
      message,
      content: encoded,
      branch,
      ...(sha ? { sha } : {}),
    });

    log.info({ owner, repo, branch, path }, "File committed");
    return { sha: (data as { commit: { sha: string } }).commit.sha };
  }

  async createPullRequest(
    owner: string,
    repo: string,
    baseBranch: string,
    headBranch: string,
    title: string,
    body: string,
  ): Promise<{ url: string; number: number }> {
    // Check if PR already exists for this branch
    const existing = await this.octokit.pulls.list({
      owner,
      repo,
      head: `${owner}:${headBranch}`,
      state: "open",
    });

    if (existing.data.length > 0) {
      const pr = existing.data[0];
      log.info({ prNumber: pr.number }, "PR already exists, returning existing");
      return { url: pr.html_url, number: pr.number };
    }

    const { data: pr } = await this.octokit.pulls.create({
      owner,
      repo,
      head: headBranch,
      base: baseBranch,
      title,
      body,
    });

    log.info({ prNumber: pr.number, url: pr.html_url }, "PR created");
    return { url: pr.html_url, number: pr.number };
  }

  async getRepoDefaultBranch(owner: string, repo: string): Promise<string> {
    const { data } = await this.octokit.repos.get({ owner, repo });
    return data.default_branch;
  }
}

import { $ } from "bun";
import path from "path";
import fs from "fs/promises";
import type { Site } from "./types.js";
import { getLogger } from "./logger.js";

const log = getLogger().child({ module: "repo" });

export class RepoManager {
  private workDir: string;
  private githubToken: string;

  constructor(workDir: string, githubToken: string) {
    this.workDir = workDir;
    this.githubToken = githubToken;
  }

  private getRepoDir(site: Site): string {
    return path.join(this.workDir, site.id);
  }

  async cloneOrUpdate(site: Site): Promise<string> {
    const repoDir = this.getRepoDir(site);
    const authUrl = site.repoUrl.replace(
      "https://github.com/",
      `https://x-access-token:***,
    );

    const exists = await this.dirExists(repoDir);

    if (exists) {
      log.info({ siteId: site.id }, "Pulling existing repo");
      await $`cd ${repoDir} && git fetch origin`.quiet();
      await $`cd ${repoDir} && git checkout ${site.branch}`.quiet();
      await $`cd ${repoDir} && git reset --hard origin/${site.branch}`.quiet();
    } else {
      log.info({ siteId: site.id, repoUrl: site.repoUrl }, "Cloning repo");
      await fs.mkdir(this.workDir, { recursive: true });
      await $`git clone --depth 1 --branch ${site.branch} ${authUrl} ${repoDir}`.quiet();
    }

    return repoDir;
  }

  async createCommit(
    repoDir: string,
    branch: string,
    message: string,
    files: string[],
  ): Promise<void> {
    await $`cd ${repoDir} && git checkout ${branch}`.quiet();

    // Stage only the specified files
    for (const file of files) {
      await $`cd ${repoDir} && git add ${file}`.quiet();
    }

    // Check if there are changes to commit
    const { stdout } = await $`cd ${repoDir} && git diff --cached --name-only`.quiet();
    if (!stdout.trim()) {
      log.info({ branch }, "No changes to commit");
      return;
    }

    await $`cd ${repoDir} && git commit -m ${message}`.quiet();
    log.info({ branch, message, files }, "Commit created");
  }

  async push(repoDir: string, branch: string): Promise<void> {
    await $`cd ${repoDir} && git push origin ${branch}`.quiet();
    log.info({ branch }, "Pushed to remote");
  }

  async checkoutOrCreateBranch(
    repoDir: string,
    branch: string,
    baseBranch: string,
  ): Promise<void> {
    // Fetch latest
    await $`cd ${repoDir} && git fetch origin`.quiet();

    // Check if remote branch exists
    try {
      await $`cd ${repoDir} && git ls-remote --heads origin ${branch}`.quiet();
      // Remote branch exists, check it out and reset to base
      await $`cd ${repoDir} && git checkout ${branch}`.quiet();
      await $`cd ${repoDir} && git reset --hard origin/${baseBranch}`.quiet();
    } catch {
      // Create new branch from base
      await $`cd ${repoDir} && git checkout ${baseBranch}`.quiet();
      await $`cd ${repoDir} && git checkout -b ${branch}`.quiet();
    }

    log.info({ repoDir, branch }, "Branch ready");
  }

  async hasChanges(repoDir: string): Promise<boolean> {
    try {
      const { stdout } = await $`cd ${repoDir} && git status --porcelain`.quiet();
      return stdout.trim().length > 0;
    } catch {
      return false;
    }
  }

  private async dirExists(dir: string): Promise<boolean> {
    try {
      const stat = await fs.stat(dir);
      return stat.isDirectory();
    } catch {
      return false;
    }
  }

  async cleanup(site: Site): Promise<void> {
    const repoDir = this.getRepoDir(site);
    try {
      await fs.rm(repoDir, { recursive: true, force: true });
      log.info({ siteId: site.id }, "Cleaned up repo directory");
    } catch (err) {
      log.warn({ siteId: site.id, err }, "Failed to clean up repo directory");
    }
  }
}

import { readFileSync } from "fs";
import { randomUUID } from "crypto";
import type { LighthouseResult, AuditFinding, Severity } from "./types.js";
import { getLogger } from "./logger.js";

const log = getLogger().child({ module: "lighthouse" });

// Lighthouse categories we care about
const CATEGORIES = [
  "performance",
  "accessibility",
  "best-practices",
  "seo",
  "pwa",
] as const;

// Thresholds for flagging findings
const SCORE_THRESHOLDS: Record<string, { warning: number; critical: number }> = {
  performance: { warning: 70, critical: 40 },
  accessibility: { warning: 80, critical: 50 },
  "best-practices": { warning: 80, critical: 50 },
  seo: { warning: 80, critical: 50 },
  pwa: { warning: 50, critical: 20 },
};

export interface LighthouseOptions {
  formFactor: "mobile" | "desktop";
  port?: number;
  chromeFlags?: string[];
}

export async function runLighthouse(
  url: string,
  options: LighthouseOptions,
): Promise<LighthouseResult> {
  const { default: lighthouse } = await import("lighthouse");
  const flags = {
    output: ["json"] as const,
    port: options.port,
    onlyCategories: [...CATEGORIES],
    formFactor: options.formFactor,
    screenEmulation: {
      disabled: false,
      mobile: options.formFactor === "mobile",
      width: options.formFactor === "mobile" ? 375 : 1350,
      height: options.formFactor === "mobile" ? 812 : 940,
      deviceScaleFactor: options.formFactor === "mobile" ? 2 : 1,
    },
    chromeFlags: options.chromeFlags ?? [],
  };

  log.info({ url, formFactor: options.formFactor }, "Running Lighthouse");

  const runnerResult = await lighthouse(url, flags, undefined);

  if (!runnerResult?.lhr) {
    throw new Error("Lighthouse returned no result");
  }

  const lhr = runnerResult.lhr;
  const reportJson = runnerResult.report;

  // Parse scores
  const scores = {
    performance: normalizeScore(lhr.categories.performance?.score),
    accessibility: normalizeScore(lhr.categories.accessibility?.score),
    bestPractices: normalizeScore(lhr.categories["best-practices"]?.score),
    seo: normalizeScore(lhr.categories.seo?.score),
    pwa: normalizeScore(lhr.categories.pwa?.score),
  };

  // Extract findings from failed audits
  const findings = extractFindings(lhr);

  const result: LighthouseResult = {
    formFactor: options.formFactor,
    scores,
    findings,
    rawUrl: options.formFactor === "mobile"
      ? `data:text/html;base64,${Buffer.from(reportJson).toString("base64")}`
      : undefined,
  };

  log.info(
    { url, formFactor: options.formFactor, scores, findingCount: findings.length },
    "Lighthouse complete",
  );

  return result;
}

function normalizeScore(score: number | null | undefined): number {
  if (score == null) return 0;
  return Math.round(score * 100);
}

function extractFindings(lhr: LH.Result): AuditFinding[] {
  const findings: AuditFinding[] = [];

  for (const cat of CATEGORIES) {
    const category = lhr.categories[cat];
    if (!category?.auditRefs) continue;

    const thresholds = SCORE_THRESHOLDS[cat];

    for (const ref of category.auditRefs) {
      const audit = lhr.audits?.[ref.id];
      if (!audit) continue;

      // Only flag audits that failed (score < 1 or scoreDisplayMode === 'error')
      if (audit.score !== null && audit.score !== 0 && audit.score !== 1) continue;
      if (audit.scoreDisplayMode === "notApplicable") continue;
      if (audit.scoreDisplayMode === "informative") continue;

      if (audit.score === 0 || audit.score === null) {
        const severity = determineSeverity(cat, audit.score, thresholds);
        findings.push({
          rule: ref.id,
          severity,
          description: audit.description || audit.title || ref.id,
          score: audit.score ?? undefined,
          url: audit.details?.items?.[0]?.url as string | undefined,
          element: (audit.details?.items?.[0]?.node as { nodeLabel?: string })?.nodeLabel,
        });
      }
    }
  }

  return findings;
}

function determineSeverity(
  category: string,
  score: number | null,
  thresholds: { warning: number; critical: number },
): Severity {
  const normalizedScore = score != null ? score * 100 : 0;
  if (normalizedScore <= thresholds.critical) return "critical";
  if (normalizedScore <= thresholds.warning) return "warning";
  return "info";
}

import type { SeoResult, AuditFinding } from "./types.js";
import { getLogger } from "./logger.js";

const log = getLogger().child({ module: "seo" });

export async function runSeoAudit(
  url: string,
  lighthouseSeoScore: number,
  lighthouseFindings: AuditFinding[],
): Promise<SeoResult> {
  log.info({ url }, "Running SEO audit");

  const findings: AuditFinding[] = [...lighthouseFindings];

  // Additional SEO checks beyond Lighthouse
  const metaTags = await fetchMetaTags(url);
  const hasSitemap = await checkSitemap(url);
  const hasRobotsTxt = await checkRobotsTxt(url);

  // Check meta title
  if (!metaTags.title || metaTags.title.length === 0) {
    findings.push({
      rule: "meta-title-missing",
      severity: "critical",
      description: "Page is missing a <title> tag",
    });
  } else if (metaTags.title.length > 60) {
    findings.push({
      rule: "meta-title-too-long",
      severity: "warning",
      description: `Title tag is ${metaTags.title.length} chars (max recommended: 60)`,
    });
  } else if (metaTags.title.length < 30) {
    findings.push({
      rule: "meta-title-too-short",
      severity: "info",
      description: `Title tag is ${metaTags.title.length} chars (min recommended: 30)`,
    });
  }

  // Check meta description
  if (!metaTags.description || metaTags.description.length === 0) {
    findings.push({
      rule: "meta-description-missing",
      severity: "critical",
      description: "Page is missing a meta description",
    });
  } else if (metaTags.description.length > 160) {
    findings.push({
      rule: "meta-description-too-long",
      severity: "warning",
      description: `Meta description is ${metaTags.description.length} chars (max recommended: 160)`,
    });
  }

  // Check canonical URL
  if (!metaTags.canonical) {
    findings.push({
      rule: "canonical-url-missing",
      severity: "warning",
      description: "Page is missing a canonical URL",
    });
  }

  // Check Open Graph tags
  const ogTags = Object.keys(metaTags).filter((k) => k.startsWith("og:"));
  if (ogTags.length === 0) {
    findings.push({
      rule: "open-graph-missing",
      severity: "warning",
      description: "No Open Graph tags found",
    });
  }

  // Check structured data
  const structuredDataValid = await checkStructuredData(url);
  if (!structuredDataValid) {
    findings.push({
      rule: "structured-data-invalid",
      severity: "warning",
      description: "Structured data (JSON-LD) is missing or invalid",
    });
  }

  // Check for H1
  const hasH1 = await checkH1(url);
  if (!hasH1) {
    findings.push({
      rule: "h1-missing",
      severity: "critical",
      description: "Page is missing an H1 heading",
    });
  }

  const result: SeoResult = {
    findings,
    metaTags,
    hasSitemap,
    hasRobotsTxt,
    structuredDataValid,
  };

  log.info(
    { url, findingCount: findings.length, hasSitemap, hasRobotsTxt },
    "SEO audit complete",
  );

  return result;
}

async function fetchMetaTags(url: string): Promise<Record<string, string>> {
  const tags: Record<string, string> = {};
  try {
    const response = await fetch(url);
    const html = await response.text();

    // Extract title
    const titleMatch = html.match(/<title[^>]*>([^<]*)<\/title>/i);
    if (titleMatch) tags.title = titleMatch[1].trim();

    // Extract meta tags
    const metaRegex = /<meta[^>]+(?:name|property)=["']([^"']+)["'][^>]+content=["']([^"']+)["']/gi;
    let match;
    while ((match = metaRegex.exec(html)) !== null) {
      const name = match[1].toLowerCase();
      const content = match[2];
      tags[name] = content;
    }

    // Extract canonical
    const canonicalMatch = html.match(/<link[^>]+rel=["']canonical["'][^>]+href=["']([^"']+)["']/i);
    if (canonicalMatch) tags.canonical = canonicalMatch[1];
  } catch (err) {
    log.warn({ url, err }, "Failed to fetch meta tags");
  }
  return tags;
}

async function checkSitemap(url: string): Promise<boolean> {
  try {
    const baseUrl = new URL(url).origin;
    const response = await fetch(`${baseUrl}/sitemap.xml`);
    return response.ok;
  } catch {
    return false;
  }
}

async function checkRobotsTxt(url: string): Promise<boolean> {
  try {
    const baseUrl = new URL(url).origin;
    const response = await fetch(`${baseUrl}/robots.txt`);
    return response.ok;
  } catch {
    return false;
  }
}

async function checkStructuredData(url: string): Promise<boolean> {
  try {
    const response = await fetch(url);
    const html = await response.text();
    return html.includes("application/ld+json") && html.includes("schema.org");
  } catch {
    return false;
  }
}

async function checkH1(url: string): Promise<boolean> {
  try {
    const response = await fetch(url);
    const html = await response.text();
    return /<h1[^>]*>[\s\S]*?<\/h1>/i.test(html);
  } catch {
    return false;
  }
}

import type { A11yResult, AuditFinding, LighthouseResult } from "./types.js";
import { getLogger } from "./logger.js";

const log = getLogger().child({ module: "a11y" });

export function runA11yAudit(
  lighthouseResult: LighthouseResult | null,
  additionalFindings: AuditFinding[] = [],
): A11yResult {
  log.info("Running accessibility audit");

  const findings: AuditFinding[] = [];
  let totalViolations = 0;
  let totalPasses = 0;

  // Extract accessibility findings from Lighthouse
  if (lighthouseResult) {
    const a11yFindings = lighthouseResult.findings.filter(
      (f) => isAccessibilityRule(f.rule),
    );
    findings.push(...a11yFindings);
    totalViolations = a11yFindings.length;
    // Estimate passes based on score
    const score = lighthouseResult.scores.accessibility;
    totalPasses = score > 0 ? Math.round((score / 100) * 50) : 0;
  }

  // Add additional findings
  findings.push(...additionalFindings);
  totalViolations += additionalFindings.length;

  // Add specific checks not covered by Lighthouse
  const extraChecks = runManualA11yChecks();
  findings.push(...extraChecks.findings);
  totalViolations += extraChecks.violations;
  totalPasses += extraChecks.passes;

  const result: A11yResult = {
    findings,
    totalViolations,
    totalPasses,
  };

  log.info(
    { violations: totalViolations, passes: totalPasses, findingCount: findings.length },
    "Accessibility audit complete",
  );

  return result;
}

function isAccessibilityRule(ruleId: string): boolean {
  const a11yPrefixes = [
    "accesskeys",
    "aria-",
    "autocomplete",
    "color-contrast",
    "document-title",
    "duplicate-id",
    "empty-heading",
    "form-field-",
    "heading-order",
    "html-has-lang",
    "html-lang-valid",
    "image-alt",
    "label",
    "link-name",
    "list",
    "listitem",
    "meta-viewport",
    "object-alt",
    "select-name",
    "skip-link",
    "tabindex",
    "td-has-header",
    "th-has-data-cells",
    "valid-lang",
    "video-caption",
  ];
  return a11yPrefixes.some((prefix) => ruleId.startsWith(prefix) || ruleId.includes(prefix));
}

function runManualA11yChecks(): { findings: AuditFinding[]; violations: number; passes: number } {
  const findings: AuditFinding[] = [];
  let violations = 0;
  let passes = 0;

  // These checks require DOM access and are noted as recommendations
  // In a full implementation, these would use axe-core or similar
  findings.push({
    rule: "keyboard-navigation",
    severity: "info",
    description: "Verify all interactive elements are keyboard accessible (manual check)",
  });
  passes++;

  findings.push({
    rule: "focus-visible",
    severity: "info",
    description: "Verify visible focus indicators on all interactive elements (manual check)",
  });
  passes++;

  findings.push({
    rule: "motion-reduction",
    severity: "info",
    description: "Verify animations respect prefers-reduced-motion (manual check)",
  });
  passes++;

  return { findings, violations, passes };
}

import { $ } from "bun";
import path from "path";
import type { DependencyResult, DependencyInfo, AuditFinding } from "./types.js";
import { getLogger } from "./logger.js";

const log = getLogger().child({ module: "dependencies" });

export async function runDependencyAudit(repoDir: string): Promise<DependencyResult> {
  log.info({ repoDir }, "Running dependency audit");

  const findings: AuditFinding[] = [];
  const dependencies: DependencyInfo[] = [];
  const safeUpdates: DependencyInfo[] = [];

  // Check if package.json exists
  const pkgPath = path.join(repoDir, "package.json");
  try {
    await Bun.file(pkgPath).text();
  } catch {
    log.warn({ repoDir }, "No package.json found, skipping dependency audit");
    return { findings, dependencies, safeUpdates };
  }

  try {
    // Run bun outdated to get dependency info
    const result = await $`cd ${repoDir} && bun outdated --json`.quiet().catch(() => null);

    if (!result) {
      findings.push({
        rule: "outdated-check-failed",
        severity: "warning",
        description: "Could not run bun outdated",
      });
      return { findings, dependencies, safeUpdates };
    }

    const outdatedData = JSON.parse(result.stdout.toString()) as Record<
      string,
      { current: string; latest: string; type?: string }
    >;

    for (const [name, info] of Object.entries(outdatedData)) {
      const depInfo = parseDependencyInfo(name, info);
      dependencies.push(depInfo);

      if (depInfo.isSafeUpdate) {
        safeUpdates.push(depInfo);
      }

      // Create findings for outdated deps
      if (depInfo.type === "major") {
        findings.push({
          rule: "dependency-major-outdated",
          severity: "warning",
          description: `${name}: ${depInfo.current} в†’ ${depInfo.latest} (major update, manual review needed)`,
        });
      } else if (depInfo.type === "minor") {
        findings.push({
          rule: "dependency-minor-outdated",
          severity: "info",
          description: `${name}: ${depInfo.current} в†’ ${depInfo.latest} (safe to auto-update)`,
        });
      } else if (depInfo.type === "patch") {
        findings.push({
          rule: "dependency-patch-outdated",
          severity: "info",
          description: `${name}: ${depInfo.current} в†’ ${depInfo.latest} (safe to auto-update)`,
        });
      }
    }

    // Check for known vulnerabilities using bun audit
    try {
      const auditResult = await $`cd ${repoDir} && bun audit --json`.quiet().catch(() => null);
      if (auditResult) {
        const auditData = JSON.parse(auditResult.stdout.toString());
        if (auditData.vulnerabilities) {
          const vulns = auditData.vulnerabilities;
          if (vulns.critical > 0) {
            findings.push({
              rule: "security-vulnerability-critical",
              severity: "critical",
              description: `${vulns.critical} critical vulnerability(ies) found`,
            });
          }
          if (vulns.high > 0) {
            findings.push({
              rule: "security-vulnerability-high",
              severity: "critical",
              description: `${vulns.high} high severity vulnerability(ies) found`,
            });
          }
        }
      }
    } catch {
      log.warn({ repoDir }, "bun audit failed, skipping vulnerability check");
    }
  } catch (err) {
    log.error({ repoDir, err }, "Dependency audit failed");
    findings.push({
      rule: "dependency-audit-error",
      severity: "warning",
      description: `Dependency audit failed: ${String(err)}`,
    });
  }

  const result: DependencyResult = {
    findings,
    dependencies,
    safeUpdates,
  };

  log.info(
    { total: dependencies.length, safeUpdates: safeUpdates.length, findingCount: findings.length },
    "Dependency audit complete",
  );

  return result;
}

function parseDependencyInfo(name: string, info: { current: string; latest: string }): DependencyInfo {
  const current = info.current.replace(/^[~^>=<\s]+/, "");
  const latest = info.latest.replace(/^[~^>=<\s]+/, "");

  const currentParts = current.split(".").map(Number);
  const latestParts = latest.split(".").map(Number);

  let type: DependencyInfo["type"] = "patch";
  if (latestParts[0] > currentParts[0]) {
    type = "major";
  } else if (latestParts.length > 1 && currentParts.length > 1 && latestParts[1] > currentParts[1]) {
    type = "minor";
  }

  // Safe updates: patch and minor only
  const isSafeUpdate = type === "patch" || type === "minor";

  return {
    name,
    current,
    latest,
    type,
    isSafeUpdate,
  };
}

export async function applySafeDependencyUpdates(repoDir: string, safeUpdates: DependencyInfo[]): Promise<string[]> {
  if (safeUpdates.length === 0) return [];

  log.info({ repoDir, count: safeUpdates.length }, "Applying safe dependency updates");
  const updated: string[] = [];

  for (const dep of safeUpdates) {
    try {
      await $`cd ${repoDir} && bun add ${dep.name}@${dep.latest}`.quiet();
      updated.push(dep.name);
      log.info({ name: dep.name, version: dep.latest }, "Dependency updated");
    } catch (err) {
      log.warn({ name: dep.name, err }, "Failed to update dependency");
    }
  }

  return updated;
}
